func roleLabelShort(name string) string {
	switch name {
	case "ROLE_ADMIN":
		return "Admin"
	case "ROLE_USER":
		return "User"
	default:
		return name
	}
}

func userHasRole(roles []models.Role, roleID int64) bool {
	for _, r := range roles {
		if r.ID == roleID {
			return true
		}
	}
	return false
}

